class SensitiveDataFilter(logging.Filter):
    """
    A logging filter that redacts sensitive information from log messages.
    This prevents passwords, tokens, API keys, and other secrets from
    being written to log files.
    """

    SENSITIVE_PATTERNS = [
        # Passwords
        (re.compile(r'("password"\s*:\s*)"[^"]*"', re.IGNORECASE), r'\1"[REDACTED]"'),
        (re.compile(r'("passwd"\s*:\s*)"[^"]*"', re.IGNORECASE), r'\1"[REDACTED]"'),
        (re.compile(r'("pass"\s*:\s*)"[^"]*"', re.IGNORECASE), r'\1"[REDACTED]"'),
        (re.compile(r'("old_password"\s*:\s*)"[^"]*"', re.IGNORECASE), r'\1"[REDACTED]"'),
        (re.compile(r'("new_password"\s*:\s*)"[^"]*"', re.IGNORECASE), r'\1"[REDACTED]"'),
        (re.compile(r'("confirm_password"\s*:\s*)"[^"]*"', re.IGNORECASE), r'\1"[REDACTED]"'),
        (re.compile(r'password=\S+', re.IGNORECASE), 'password=[REDACTED]'),

        # Authorization tokens
        (re.compile(r'(Authorization:\s*Bearer\s+)\S+', re.IGNORECASE), r'\1[REDACTED]'),
        (re.compile(r'(Authorization:\s*Basic\s+)\S+', re.IGNORECASE), r'\1[REDACTED]'),
        (re.compile(r'("authorization"\s*:\s*)"[^"]*"', re.IGNORECASE), r'\1"[REDACTED]"'),
        (re.compile(r'("token"\s*:\s*)"[^"]*"', re.IGNORECASE), r'\1"[REDACTED]"'),
        (re.compile(r'("access_token"\s*:\s*)"[^"]*"', re.IGNORECASE), r'\1"[REDACTED]"'),
        (re.compile(r'("refresh_token"\s*:\s*)"[^"]*"', re.IGNORECASE), r'\1"[REDACTED]"'),
        (re.compile(r'("api_key"\s*:\s*)"[^"]*"', re.IGNORECASE), r'\1"[REDACTED]"'),
        (re.compile(r'("apikey"\s*:\s*)"[^"]*"', re.IGNORECASE), r'\1"[REDACTED]"'),

        # Session IDs
        (re.compile(r'("session_id"\s*:\s*)"[^"]*"', re.IGNORECASE), r'\1"[REDACTED]"'),
        (re.compile(r'("sessionid"\s*:\s*)"[^"]*"', re.IGNORECASE), r'\1"[REDACTED]"'),

        # Credit card numbers (basic pattern)
        (re.compile(r'\b\d{4}[\s-]?\d{4}[\s-]?\d{4}[\s-]?\d{4}\b'), '[REDACTED_CC]'),

        # SSN pattern
        (re.compile(r'\b\d{3}-\d{2}-\d{4}\b'), '[REDACTED_SSN]'),

        # Cookie headers
        (re.compile(r'("cookie"\s*:\s*)"[^"]*"', re.IGNORECASE), r'\1"[REDACTED]"'),
        (re.compile(r'(Cookie:\s*)\S+', re.IGNORECASE), r'\1[REDACTED]'),

        # Secret keys
        (re.compile(r'("secret"\s*:\s*)"[^"]*"', re.IGNORECASE), r'\1"[REDACTED]"'),
        (re.compile(r'("secret_key"\s*:\s*)"[^"]*"', re.IGNORECASE), r'\1"[REDACTED]"'),
    ]

    def filter(self, record):
        """Apply redaction patterns to the log message."""
        if isinstance(record.msg, str):
            record.msg = self._redact(record.msg)
        if record.args:
            record.args = tuple(
                self._redact(arg) if isinstance(arg, str) else arg
                for arg in record.args
            )
        return True

    def _redact(self, message):
        """Replace sensitive patterns in a string."""
        for pattern, replacement in self.SENSITIVE_PATTERNS:
            message = pattern.sub(replacement, message)
        return message


def sanitize_dict(data, sensitive_keys=None):
    """
    Recursively sanitize a dictionary by redacting values of sensitive keys.
    Returns a new dictionary with sensitive values replaced.
    """
    if sensitive_keys is None:
        sensitive_keys = {
            'password', 'passwd', 'pass', 'token', 'access_token',
            'refresh_token', 'authorization', 'api_key', 'apikey',
            'secret', 'secret_key', 'session_id', 'sessionid',
            'cookie', 'set-cookie', 'old_password', 'new_password',
            'confirm_password', 'credit_card', 'card_number', 'cvv',
            'ssn', 'social_security',
        }

    if not isinstance(data, dict):
        return data

    sanitized = {}
    for key, value in data.items():
        if key.lower() in sensitive_keys:
            sanitized[key] = '[REDACTED]'
        elif isinstance(value, dict):
            sanitized[key] = sanitize_dict(value, sensitive_keys)
        elif isinstance(value, list):
            sanitized[key] = [
                sanitize_dict(item, sensitive_keys) if isinstance(item, dict) else item
                for item in value
            ]
        else:
            sanitized[key] = value
    return sanitized


def sanitize_headers(headers):
    """Sanitize HTTP headers, redacting sensitive ones."""
    sensitive_headers = {
        'authorization', 'cookie', 'set-cookie', 'x-api-key',
        'x-auth-token', 'proxy-authorization',
    }
    sanitized = {}
    for key, value in headers.items():
        if key.lower() in sensitive_headers:
            sanitized[key] = '[REDACTED]'
        else:
            sanitized[key] = value
    return sanitized


