class RequestLogAdapter(logging.LoggerAdapter):
    """Adds request context to log messages."""

    def process(self, msg, kwargs):
        extra = kwargs.get('extra', {})
        extra['request_id'] = getattr(g, 'request_id', 'N/A')
        kwargs['extra'] = extra
        return msg, kwargs


