def require_auth(f):
    """Decorator to require authentication for endpoints."""
    @wraps(f)
    def decorated(*args, **kwargs):
        auth_header = request.headers.get('Authorization', '')

        if not auth_header.startswith('Bearer '):
            log.warning('Missing or malformed Authorization header on %s %s',
                        request.method, request.path)
            return jsonify({'error': 'Authorization required'}), 401

        token = auth_header.split(' ', 1)[1]

        # Validate token (DO NOT log the actual token)
        token_data = VALID_TOKENS.get(token)
        if not token_data:
            # Log the failure without the token value
            log.warning('Invalid or expired token used on %s %s from %s',
                        request.method, request.path, request.remote_addr)
            return jsonify({'error': 'Invalid or expired token'}), 401

        if token_data['expires'] < datetime.utcnow():
            log.warning('Expired token used by user_id=%s on %s %s',
                        token_data.get('user_id', 'unknown'),
                        request.method, request.path)
            del VALID_TOKENS[token]
            return jsonify({'error': 'Token expired'}), 401

        g.current_user = token_data
        log.info('Authenticated user_id=%s, username=%s',
                 token_data.get('user_id'), token_data.get('username'))
        return f(*args, **kwargs)

    return decorated


def generate_token(user):
    """Generate a simple token for demonstration."""
    token = str(uuid.uuid4())
    VALID_TOKENS[token] = {
        'user_id': user['id'],
        'username': user['username'],
        'role': user['role'],
        'expires': datetime.utcnow() + timedelta(hours=1),
    }
    return token


