@app.route('/api/login', methods=['POST'])
def login():
    """
    Login endpoint.
    IMPORTANT: We log the login attempt (username, success/failure)
    but NEVER log the password or generated token values.
    """
    if not request.is_json:
        log.warning('Login attempt with non-JSON content type from %s',
                    request.remote_addr)
        return jsonify({'error': 'Content-Type must be application/json'}), 400

    data = request.get_json(silent=True)
    if not data:
        log.warning('Login attempt with empty body from %s', request.remote_addr)
        return jsonify({'error': 'Missing request body'}), 400

    username = data.get('username', '')
    password = data.get('password', '')

    if not username or not password:
        # Log that fields are missing, but NOT the actual values
        log.warning('Login attempt with missing credentials from %s',
                    request.remote_addr)
        return jsonify({'error': 'Username and password are required'}), 400

    # Log the username attempting login (but NEVER the password)
    log.info('Login attempt for username=%s from %s',
             username, request.remote_addr)

    user = USERS.get(username)
    if not user or not verify_password(user['password_hash'], password):
        # Log failed login with username only - NEVER log the password
        log.warning(
            'Failed login attempt for username=%s from %s - invalid credentials',
            username, request.remote_addr
        )
        return jsonify({'error': 'Invalid credentials'}), 401

    token = generate_token(user)

    # Log successful login but NEVER log the token
    log.info('Successful login for username=%s, user_id=%s from %s',
             username, user['id'], request.remote_addr)

    return jsonify({
        'message': 'Login successful',
        'token': token,  # Sent to client but redacted in logs by our filter
        'user': {
            'id': user['id'],
            'username': user['username'],
            'role': user['role'],
        }
    })


@app.route('/api/logout', methods=['POST'])
@require_auth
def logout():
    """Logout endpoint - invalidate token."""
    auth_header = request.headers.get('Authorization', '')
    token = auth_header.split(' ', 1)[1] if ' ' in auth_header else ''

    if token in VALID_TOKENS:
        del VALID_TOKENS[token]

    # Log logout without the token value
    log.info('User user_id=%s, username=%s logged out',
             g.current_user.get('user_id'), g.current_user.get('username'))

    return jsonify({'message': 'Logged out successfully'})


